package fr.heroesworld.titlescreen;

import net.minecraft.client.MinecraftClient;
import net.minecraft.client.gui.DrawContext;
import net.minecraft.client.texture.NativeImage;
import net.minecraft.client.texture.NativeImageBackedTexture;
import net.minecraft.util.Identifier;

import java.io.ByteArrayInputStream;
import java.util.Base64;

/**
 * Icones du dock, embarquees en base64 (PNG 96x96 anti-crenelees) chargees en memoire.
 * Aucune dependance a un fichier binaire -> zero risque de corruption. Repli si echec.
 */
public final class HWIcons {
    private static final String[] B64 = {
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        // 20 scoreboard / 21 tchat / 22 crosshair / 23 waypoints (generees, or/corail)
        "",
        "",
        "",
        ""
    };
    private static final Identifier[] IDS = new Identifier[B64.length];
    private static boolean loaded = false;
    private HWIcons() {}

    private static void ensure() {
        if (loaded) return;
        loaded = true;
        for (int i = 0; i < B64.length; i++) {
            try {
                byte[] bytes = Base64.getDecoder().decode(B64[i]);
                NativeImage img = NativeImage.read(new ByteArrayInputStream(bytes));
                NativeImageBackedTexture tex = new NativeImageBackedTexture(img);
                tex.setFilter(true, false);
                Identifier id = new Identifier("heroworld", "icon_dyn_" + i);
                MinecraftClient.getInstance().getTextureManager().registerTexture(id, tex);
                IDS[i] = id;
            } catch (Throwable t) {
                IDS[i] = null;
            }
        }
    }

    public static boolean draw(DrawContext ctx, int kind, int cx, int cy, int size) {
        ensure();
        int idx = kind - 1;
        if (idx < 0 || idx >= IDS.length || IDS[idx] == null) return false;
        int half = size / 2;
        ctx.drawTexture(IDS[idx], cx - half, cy - half, size, size, 0f, 0f, 96, 96, 96, 96);
        return true;
    }
}
